+#[inline]
+unsafe fn bounded_wide_string_len(ptr: *const WcharT) -> usize {
+    let bound = known_remaining(ptr as usize).map(|bytes| bytes / std::mem::size_of::<WcharT>());
+    match bound {
+        Some(limit) => {
+            for i in 0..limit {
+                if unsafe { *ptr.add(i) } == 0 {
+                    return i;
+                }
+            }
+            limit
+        }
+        None => {
+            let mut len = 0usize;
+            while unsafe { *ptr.add(len) } != 0 {
+                len += 1;
+            }
+            len
+        }
+    }
+}
